{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 2f);
var wrinkleStrength = GetFloat(parameters, "wrinkleStrength", 0.6f);
var wrinkleAngle = GetFloat(parameters, "wrinkleAngle", 0f);
var grainAmount = GetFloat(parameters, "grainAmount", 0.4f);
var leatherColor = GetColor(parameters, "leatherColor", Color.FromRgb(140, 80, 50));
var deepColor = GetColor(parameters, "deepColor", Color.FromRgb(80, 45, 30));
var highlightColor = GetColor(parameters, "highlightColor", Color.FromRgb(200, 170, 140));
var colorVar = GetFloat(parameters, "colorVariation", 0.15f);
var glossiness = GetFloat(parameters, "glossiness", 0.3f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var hasBase = inputs.Length > 0 && inputs[0] != null;
var input = hasBase ? inputs[0]! : null;
var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var lR = leatherColor.R / 255f; var lG = leatherColor.G / 255f; var lB = leatherColor.B / 255f;
var dR = deepColor.R / 255f; var dG = deepColor.G / 255f; var dB = deepColor.B / 255f;
var hR = highlightColor.R / 255f; var hG = highlightColor.G / 255f; var hB = highlightColor.B / 255f;

var angleRad = wrinkleAngle * MathF.PI / 180f;
var period = Math.Max(1, (int)MathF.Round(scale * 6f));

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Rotate coordinates for directional wrinkles
    var ru = u * MathF.Cos(angleRad) - v * MathF.Sin(angleRad);
    var rv = u * MathF.Sin(angleRad) + v * MathF.Cos(angleRad);

    // --- Multi-scale wrinkle noise ---
    // Large wrinkles (stretched along direction for crease lines)
    var wrinkleLarge = TileableFractalNoise(
        ru * scale * 0.5f, rv * scale * 2f,
        period, 3, 0.6f, 2.2f, seed);

    // Medium wrinkles (cross-direction for pebbling)
    var wrinkleMedium = TileableFractalNoise(
        u * scale * 1.5f, v * scale * 1.5f,
        period, 2, 0.5f, 2f, seed + 100);

    // Fine grain (high frequency)
    var grain = 0f;
    if (grainAmount > 0f)
    {
        grain = TileableFractalNoise(
            u * scale * 6f, v * scale * 6f,
            Math.Max(1, period / 2), 2, 0.5f, 2.5f, seed + 200);
    }

    // Combine wrinkles into a height map
    var height = wrinkleLarge * 0.6f + wrinkleMedium * 0.3f + grain * grainAmount * 0.1f;
    height = Math.Clamp(height, 0f, 1f);

    // Wrinkle strength remapping
    if (wrinkleStrength < 1f)
    {
        height = Lerp(0.5f, height, wrinkleStrength);
    }

    // --- Base surface ---
    float baseR, baseG, baseB;
    if (hasBase && input != null)
    {
        var (br, bg, bb, _) = input.GetPixel(x, y);
        baseR = br; baseG = bg; baseB = bb;
    }
    else
    {
        baseR = lR; baseG = lG; baseB = lB;
    }

    // Color variation across the surface
    var colorNoise = TileableFractalNoise(
        u * 2f, v * 2f,
        Math.Max(1, (int)MathF.Round(2f)), 2, 0.5f, 2f, seed + 300);
    var varAmt = (colorNoise - 0.5f) * colorVar;
    baseR = Math.Clamp(baseR + varAmt, 0f, 1f);
    baseG = Math.Clamp(baseG + varAmt * 0.7f, 0f, 1f);
    baseB = Math.Clamp(baseB + varAmt * 0.5f, 0f, 1f);

    // --- Wrinkle shading ---
    // Creases are dark valleys, peaks are light
    var crease = 1f - height; // Invert: low height = deep crease
    crease = MathF.Pow(crease, 1.5f) * wrinkleStrength;

    // Deep crease color
    var r = Lerp(baseR, dR, crease * 0.6f);
    var g = Lerp(baseG, dG, crease * 0.6f);
    var b = Lerp(baseB, dB, crease * 0.6f);

    // --- Specular sheen on raised areas ---
    if (glossiness > 0f)
    {
        var specBase = MathF.Pow(height, 3f) * glossiness * 0.3f;
        r = Math.Clamp(r + hR * specBase, 0f, 1f);
        g = Math.Clamp(g + hG * specBase * 0.8f, 0f, 1f);
        b = Math.Clamp(b + hB * specBase * 0.6f, 0f, 1f);
    }

    // Fine pore detail
    if (grainAmount > 0f)
    {
        var poreNoise = TileableFractalNoise(
            u * scale * 10f, v * scale * 10f,
            Math.Max(1, period / 3), 1, 0.5f, 2f, seed + 400);
        var pore = (poreNoise - 0.5f) * grainAmount * 0.06f;
        r = Math.Clamp(r + pore, 0f, 1f);
        g = Math.Clamp(g + pore * 0.8f, 0f, 1f);
        b = Math.Clamp(b + pore * 0.6f, 0f, 1f);
    }

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
